import{ALIAS_TAG,BETA_TAG,INTERNAL_TAG,PUBLIC_TAG}from"../constants.js";export const splitTags=s=>s.flatMap(s=>s.split(",")).reduce(([s,t],o)=>{const a=o.match(/[a-zA-Z]+/);return a&&(o.startsWith("-")?t:s).push(a[0]),[s,t]},[[],[]]);const hasTag=(s,t)=>s.some(s=>t.has(`@${s}`));export const shouldIgnore=(s,t)=>{const[o,a]=t;return o.length>0&&!hasTag(o,s)||!!(a.length>0&&hasTag(a,s))};export const getShouldIgnoreHandler=s=>t=>t.has(PUBLIC_TAG)||t.has(BETA_TAG)||t.has(ALIAS_TAG)||s&&t.has(INTERNAL_TAG);export const getShouldIgnoreTagHandler=s=>t=>shouldIgnore(t,s);